<div><div class="mb-6 flex items-center justify-between"><div><h1 class="text-2xl font-bold text-slate-900">Carga masiva de productos</h1><p class="text-sm text-slate-500">Procesamiento síncrono, validación por fila y auditoría normal.</p></div><button wire:click="downloadTemplate" class="rounded-lg border border-slate-300 bg-white px-4 py-2 text-sm font-semibold text-slate-700">Descargar plantilla</button></div><div class="max-w-3xl rounded-xl bg-white p-6 shadow-sm"><input type="file" wire:model="file" accept=".xlsx,.xls,.csv" class="block w-full text-sm"><div wire:loading wire:target="file" class="mt-2 text-sm text-slate-500">Preparando archivo...</div><button wire:click="import" class="mt-5 rounded-lg bg-indigo-600 px-4 py-2 text-sm font-semibold text-white">Importar productos</button>@if($result)<div class="mt-6 rounded-lg bg-slate-50 p-4 text-sm"><p>Procesadas: <strong>{{ $result['processed'] }}</strong> · Creadas: <strong>{{ $result['created'] }}</strong> · Actualizadas: <strong>{{ $result['updated'] }}</strong></p>@if($result['errors'])<div class="mt-4 text-rose-700"><p class="font-semibold">Errores por fila:</p>@foreach($result['errors'] as $line => $errors)<p class="mt-1">Fila {{ $line }}: {{ implode(' ', $errors) }}</p>@endforeach</div>@endif</div>@endif</div></div>
